const body = $input.first().json.body;

const payload = {
  title: body.title || '',
  notes: body.notes || '',
  productType: body.productType || 'sculpture',
  marketplace: body.marketplace || 'both',
  madeToOrder: !!body.madeToOrder,
  priceTier: body.priceTier || 'auto',
  voiceAnchors: body.voiceAnchors || ['warm', 'maker'],
  imageData: body.image?.data || '',
  imageMimeType: body.image?.mimeType || 'image/jpeg',
  imageName: body.image?.filename || 'product.jpg',
  shopEtsy: body.shop?.etsy || 'Your Shop',
  shopShopify: body.shop?.shopify || 'your-shop',
  brandName: body.shop?.etsy || 'Your Shop',
  timestamp: body.timestamp || new Date().toISOString()
};

const visionText = `You are a senior product photographer and product researcher analyzing an item for an Etsy and Shopify listing.\n\nUSER NOTES:\nTitle: ${payload.title}\nProduct type: ${payload.productType}\nNotes: ${payload.notes || 'none'}\n\nReturn a structured JSON object with these fields ONLY, no markdown:\n{\n  "visualDescription": "2-3 sentence visual description",\n  "likelySubject": "most likely subject/IP if recognizable, or 'original design'",\n  "materialsObserved": ["likely", "materials"],\n  "finishQuality": "hand-painted | airbrushed | unpainted | matte | glossy | weathered",\n  "colorPalette": ["primary", "colors"],\n  "estimatedScale": "miniature | desk | tabletop | bust-size | life-size | unclear",\n  "distinctiveDetails": ["specific details worth highlighting"],\n  "craftsmanshipNotes": "sentence on visible craft quality",\n  "recommendedAngles": ["angles to photograph"],\n  "aiVisibilityScore": 1,\n  "reasoning": "why you scored visibility as you did"\n}\n\nReturn ONLY valid JSON, no preamble.`;

payload.visionRequestBody = {
  contents: [{
    parts: [
      { text: visionText },
      { inline_data: { mime_type: payload.imageMimeType, data: payload.imageData } }
    ]
  }],
  generationConfig: { temperature: 0.4, responseMimeType: 'application/json' }
};

return [{ json: payload }];

const original = $('Prep payload').first().json;
const response = $input.first().json;

let vision = {};
try {
  const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  vision = JSON.parse(text);
} catch (e) {
  vision = { error: 'Failed to parse Gemini Vision response', raw: response };
}

const data = { ...original, vision };

const researchText = `You are an Etsy and Shopify SEO researcher with live web search. Research the following product.\n\nTITLE: ${data.title}\nTYPE: ${data.productType}\nVISUAL: ${JSON.stringify(data.vision)}\nNOTES: ${data.notes || 'none'}\nMARKETPLACE: ${data.marketplace}\n\nUsing live Google search, research:\n1. Comparable products on Etsy and Shopify with price ranges\n2. Top-performing search keywords\n3. Trends, fan communities, cultural moments\n4. IP/copyright caveats\n5. Top Etsy tags for this niche\n\nReturn ONLY valid JSON:\n{"comparables":[{"description":"brief","priceRange":"$X-$Y","source":"etsy|shopify|other"}],"suggestedPriceRange":"$X - $Y","topKeywords":["15 keywords"],"trendingTags":["trending"],"culturalContext":"sentence","ipNotes":"sentence or No IP concerns","buyerPersona":"who buys and why","sources":[]}`;

data.researchRequestBody = {
  contents: [{ parts: [{ text: researchText }] }],
  tools: [{ googleSearch: {} }],
  generationConfig: { temperature: 0.5 }
};

return [{ json: data }];

const prior = $('Parse vision').first().json;
const response = $input.first().json;

let research = {};
let sources = [];

try {
  const candidate = response.candidates?.[0];
  const text = candidate?.content?.parts?.[0]?.text || '{}';
  const clean = text.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
  research = JSON.parse(clean);

  const groundingChunks = candidate?.groundingMetadata?.groundingChunks || [];
  sources = groundingChunks.map(chunk => ({
    url: chunk.web?.uri || '',
    title: chunk.web?.title || chunk.web?.uri || '',
    citation: ''
  })).filter(s => s.url);

  const supports = candidate?.groundingMetadata?.groundingSupports || [];
  supports.forEach(s => {
    const idx = s.groundingChunkIndices?.[0];
    if (idx != null && sources[idx] && s.segment?.text && !sources[idx].citation) {
      sources[idx].citation = s.segment.text.substring(0, 200);
    }
  });
} catch (e) {
  research = { error: 'Failed to parse Gemini Research', raw: response };
}

const data = { ...prior, research, sources };

const voiceAnchors = (data.voiceAnchors || ['warm','maker']).join(', ');
const systemPrompt = `You are the in-house copywriter for ${data.brandName}, a maker shop. Write Etsy and Shopify listing copy that sounds like a real maker, not generic AI marketing. Brand anchors: ${voiceAnchors}. Lean into specifics, materials, time, craft. Avoid: 'elevate your space', 'perfect addition', 'whether you are', em-dashes as breath pauses, and other AI tells.`;

const userPrompt = `Write listing description copy.\n\nPRODUCT BRIEF\nTitle: ${data.title}\nType: ${data.productType}\nMade-to-order: ${data.madeToOrder}\nNotes: ${data.notes || 'none'}\n\nVISION\n${JSON.stringify(data.vision)}\n\nRESEARCH\n${JSON.stringify(data.research)}\n\nSHOP\nEtsy: ${data.shopEtsy}\nShopify: ${data.shopShopify}\n\nReturn ONLY valid JSON, no preamble, no markdown:\n{"etsyTitle":"under 140 chars","shopifyTitle":"60-70 chars for Google Shopping","etsyDescription":"4-7 paragraph maker-voice description, plain text with double line breaks","shopifyBodyHtml":"same content with p, h3, ul, li tags. Include Details h3 with bullet list.","materials":["specific materials"],"shortHook":"one-line hook under 80 chars"}`;

data.claudeRequestBody = {
  model: 'claude-opus-4-5',
  max_tokens: 3000,
  system: systemPrompt,
  messages: [{ role: 'user', content: userPrompt }]
};

return [{ json: data }];

const prior = $('Parse research').first().json;
const response = $input.first().json;

let claude = {};
try {
  const text = response.content?.[0]?.text || '{}';
  const clean = text.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
  claude = JSON.parse(clean);
} catch (e) {
  claude = { error: 'Failed to parse Claude response', raw: response };
}

const data = { ...prior, claude };

const gptUserContent = `Generate short-form variants for this product.\n\nTitle: ${data.claude?.etsyTitle || data.title}\nHook: ${data.claude?.shortHook || ''}\nProduct type: ${data.productType}\nResearch keywords: ${(data.research?.topKeywords || []).join(', ')}\nTrending tags: ${(data.research?.trendingTags || []).join(', ')}\nBuyer persona: ${data.research?.buyerPersona || ''}\n\nReturn ONLY valid JSON in this exact shape:\n{"titleVariants":["5 alternative Etsy titles, each different angle, under 140 chars"],"etsyTags":["exactly 13 tags, each 20 chars or under, mix of broad + long-tail"],"shopifyTags":["10-15 Shopify tags optimized for collection filtering"],"adHeadlines":["6 ad headlines under 30 chars each"],"adPrimaryText":"90-125 word primary ad text for Meta/Facebook ads, conversational, single paragraph","pinterestPin":"Pinterest pin description, 200-300 chars, with 3-5 hashtags at end","instagramCaption":"Instagram caption with line breaks and 8-12 niche hashtags grouped at bottom","emailSubjects":["5 email subject lines under 50 chars each"],"category":"best Etsy category path","occasion":"primary occasion tag if applicable, else empty string"}`;

data.gptRequestBody = {
  model: 'gpt-5',
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: 'You are an Etsy and ad-copy specialist. You write punchy short-form variants that win clicks. Avoid AI tells. Always return valid JSON only.' },
    { role: 'user', content: gptUserContent }
  ]
};

return [{ json: data }];

const prior = $('Parse claude').first().json;
const response = $input.first().json;

let gpt = {};
try {
  const text = response.choices?.[0]?.message?.content || '{}';
  gpt = JSON.parse(text);
} catch (e) {
  gpt = { error: 'Failed to parse GPT response', raw: response };
}

const data = { ...prior, gpt };

const seoText = `You are a technical SEO specialist for Shopify and Google Merchant Center.\n\nProduct title: ${data.claude?.shopifyTitle || data.title}\nDescription: ${data.claude?.etsyDescription || ''}\nMaterials: ${(data.claude?.materials || []).join(', ')}\nProduct type: ${data.productType}\nKeywords: ${(data.research?.topKeywords || []).join(', ')}\nPrice tier: ${data.priceTier}\nSuggested price: ${data.research?.suggestedPriceRange || ''}\nMade-to-order: ${data.madeToOrder}\nVendor: ${data.brandName}\n\nReturn ONLY valid JSON, no markdown:\n{"metaTitle":"50-60 chars","metaDescription":"150-160 chars with CTA","altText":"100-125 chars","urlHandle":"slug","productType":"type","vendor":"${data.brandName}","googleProductCategory":"category","structuredData":{"@context":"https://schema.org/","@type":"Product","name":"","description":"","brand":{"@type":"Brand","name":"${data.brandName}"},"category":"","material":"","offers":{"@type":"Offer","priceCurrency":"USD","price":"placeholder","availability":""}},"suggestedPrice":""}`;

data.seoRequestBody = {
  contents: [{ parts: [{ text: seoText }] }],
  generationConfig: { temperature: 0.3, responseMimeType: 'application/json' }
};

return [{ json: data }];

const prior = $('Parse gpt').first().json;
const response = $input.first().json;

let seo = {};
try {
  const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  seo = JSON.parse(text);
} catch (e) {
  seo = { error: 'Failed to parse Gemini SEO', raw: response };
}

const { vision, research, claude, gpt, sources } = prior;

const out = {
  ok: true,
  generatedAt: new Date().toISOString(),
  input: {
    title: prior.title,
    productType: prior.productType,
    notes: prior.notes
  },
  etsy: {
    title: claude.etsyTitle || '',
    description: claude.etsyDescription || '',
    tags: gpt.etsyTags || [],
    materials: claude.materials || [],
    category: gpt.category || '',
    occasion: gpt.occasion || '',
    suggestedPrice: seo.suggestedPrice || research.suggestedPriceRange || ''
  },
  shopify: {
    title: claude.shopifyTitle || claude.etsyTitle || '',
    metaTitle: seo.metaTitle || '',
    metaDescription: seo.metaDescription || '',
    bodyHtml: claude.shopifyBodyHtml || '',
    productType: seo.productType || prior.productType,
    vendor: seo.vendor || prior.brandName,
    tags: gpt.shopifyTags || [],
    altText: seo.altText || '',
    urlHandle: seo.urlHandle || '',
    googleProductCategory: seo.googleProductCategory || '',
    structuredData: seo.structuredData || null
  },
  adCopy: {
    titleVariants: gpt.titleVariants || [],
    headlines: gpt.adHeadlines || [],
    primaryText: gpt.adPrimaryText || '',
    pinterest: gpt.pinterestPin || '',
    instagram: gpt.instagramCaption || '',
    emailSubjects: gpt.emailSubjects || []
  },
  sources: sources || [],
  research: {
    comparables: research.comparables || [],
    suggestedPriceRange: research.suggestedPriceRange || '',
    buyerPersona: research.buyerPersona || '',
    culturalContext: research.culturalContext || '',
    ipNotes: research.ipNotes || ''
  },
  vision
};

return [{ json: out }];
